1	import { useCallback, useEffect, useMemo, useState } from 'preact/hooks';
2	import {
3	  workoutKeyForDay,
4	  suggestWeight,
5	  getLastWeight,
6	  buildLatestWeightedMap,
7	} from './logic/progression';
8	import { resolveExercise } from './logic/resolveExercise';
9	import {
10	  DEFAULT_STATE,
11	  deleteLogEntry,
12	  loadLog,
13	  loadProgram,
14	  loadState,
15	  putLogEntry,
16	  saveState,
17	} from './state';
18	import {
19	  applyProgramImportFromFile,
20	  formatProgramImportMessage,
21	} from './logic/exportImport';
22	import type { LogEntry, LogMap, Phase, Program, WorkoutState } from './types';
23	import { ExerciseCard } from './components/ExerciseCard';
24	import { VideoModal } from './components/VideoModal';
25	
26	function getCurrentPhase(program: Program | null, state: WorkoutState): Phase | null {
27	  if (!program) return null;
28	  return program.phases.find((p) => p.id === state.currentPhase) ?? null;
29	}
30	
31	interface VideoState {
32	  videoId: string;
33	  start?: number;
34	}
35	
36	export function Workouts() {
37	  const [state, setState] = useState<WorkoutState>(DEFAULT_STATE);
38	  const [log, setLog] = useState<LogMap>({});
39	  const [video, setVideo] = useState<VideoState | null>(null);
40	  const [importMessage, setImportMessage] = useState<string | null>(null);
41	  const [loaded, setLoaded] = useState(false);
42	  // Programs are runtime data: they arrive via import or (future) AI
43	  // generation, persisted to the 'program' store in flux-db. No bundled
44	  // default — the empty state below covers a fresh install.
45	  const [program, setProgram] = useState<Program | null>(null);
46	
47	  useEffect(() => {
48	    (async () => {
49	      const [s, l, p] = await Promise.all([loadState(), loadLog(), loadProgram()]);
50	      setState(s);
51	      setLog(l);
52	      setProgram(p);
53	      setLoaded(true);
54	    })();
55	  }, []);
56	
57	  function triggerProgramImport() {
58	    document
59	      .querySelector<HTMLInputElement>('[data-testid="import-program-input"]')
60	      ?.click();
61	  }
62	
63	  const phase = getCurrentPhase(program, state);
64	  const workoutKey = phase ? workoutKeyForDay(phase, state.globalDay) : null;
65	  const workout = phase && workoutKey && workoutKey !== 'Rest' ? phase.workouts[workoutKey] : null;
66	  const week = Math.floor((state.globalDay - 1) / 7) + 1;
67	
68	  const resolvedExercises = useMemo(
69	    () => workout?.exercises.map(resolveExercise) ?? [],
70	    [workout],
71	  );
72	
73	  const completedCount = useMemo(() => {
74	    if (!workout) return 0;
75	    return resolvedExercises.reduce((count, _ex, i) => {
76	      const key = `${state.globalDay}_${i}`;
77	      return count + (log[key]?.completed ? 1 : 0);
78	    }, 0);
79	  }, [log, state.globalDay, workout, resolvedExercises]);
80	
81	  // Compute latest-weighted-entry-per-exercise once per log change so render
82	  // is O(M) instead of O(M*N) (scanning the full log for every exercise).
83	  const latestWeights = useMemo(() => buildLatestWeightedMap(log), [log]);
84	
85	  const onLog = useCallback(
86	    (key: string, partial: Partial<LogEntry>, options?: { remove?: boolean }) => {
87	      const existing = log[key];
88	      const merged: Partial<LogEntry> = { ...existing, ...partial };
89	
90	      for (const k of Object.keys(merged) as (keyof LogEntry)[]) {
91	        if (merged[k] === undefined) delete merged[k];
92	      }
93	
94	      const meaningless =
95	        options?.remove ||
96	        (!merged.weight &&
97	          !merged.difficulty &&
98	          !merged.notes &&
99	          !merged.completed);
100	
101	      if (meaningless) {
102	        setLog((prev) => {
103	          if (!(key in prev)) return prev;
104	          const next = { ...prev };
105	          delete next[key];
106	          return next;
107	        });
108	        deleteLogEntry(key).catch(() => {});
109	      } else {
110	        const entry: LogEntry = {
111	          exercise: merged.exercise ?? existing?.exercise ?? '',
112	          day: merged.day ?? existing?.day ?? state.globalDay,
113	          timestamp: merged.timestamp ?? Date.now(),
114	          ...merged,
115	        };
116	        setLog((prev) => ({ ...prev, [key]: entry }));
117	        putLogEntry(key, entry).catch(() => {});
118	      }
119	    },
120	    [log, state.globalDay],
121	  );
122	
123	  function nextDay() {
124	    if (state.globalDay >= 365) return;
125	    let nextPhaseId = state.currentPhase;
126	    const day = state.globalDay + 1;
127	    if (phase && program) {
128	      const daysInPhase = phase.duration_weeks * 7;
129	      if (day > daysInPhase) {
130	        const idx = program.phases.findIndex((p) => p.id === phase.id);
131	        if (idx >= 0 && idx < program.phases.length - 1) {
132	          nextPhaseId = program.phases[idx + 1].id;
133	        }
134	      }
135	    }
136	    const ns: WorkoutState = { globalDay: day, currentPhase: nextPhaseId };
137	    setState(ns);
138	    saveState(ns).catch(() => {});
139	  }
140	
141	  function prevDay() {
142	    if (state.globalDay <= 1) return;
143	    const day = state.globalDay - 1;
144	    let nextPhaseId = state.currentPhase;
145	    if (phase && program) {
146	      const idx = program.phases.findIndex((p) => p.id === phase.id);
147	      if (idx > 0) {
148	        const prev = program.phases[idx - 1];
149	        if (day <= prev.duration_weeks * 7) nextPhaseId = prev.id;
150	      }
151	    }
152	    const ns: WorkoutState = { globalDay: day, currentPhase: nextPhaseId };
153	    setState(ns);
154	    saveState(ns).catch(() => {});
155	  }
156	
157	  async function handleProgramImport(e: Event) {
158	    const input = e.target as HTMLInputElement;
159	    const file = input.files?.[0];
160	    input.value = '';
161	    if (!file) return;
162	    try {
163	      const result = await applyProgramImportFromFile(file);
164	      const p = await loadProgram();
165	      setProgram(p);
166	      setImportMessage(formatProgramImportMessage(result));
167	    } catch (err) {
168	      setImportMessage(
169	        'Import failed: ' + (err instanceof Error ? err.message : 'unknown error'),
170	      );
171	    }
172	  }
173	
174	  if (!loaded) {
175	    return (
176	      <section class="flex h-full items-center justify-center">
177	        <p class="text-xs uppercase tracking-[0.2em] text-flux-text-tertiary">Loading workout…</p>
178	      </section>
179	    );
180	  }
181	
182	  const totalExercises = resolvedExercises.length;
183	  const progressPercent = totalExercises > 0 ? (completedCount / totalExercises) * 100 : 0;
184	
185	  return (
186	    <section class="mx-auto max-w-2xl space-y-6" data-testid="workouts-root">
187	      <header class="flex flex-col items-center gap-2 pt-2 text-center">
188	        <h1 class="text-sm font-medium uppercase tracking-[0.28em] text-flux-text-primary">
189	          Workouts
190	        </h1>
191	        <div class="flex items-baseline gap-2 text-[10px] uppercase tracking-[0.2em] text-flux-text-tertiary">
192	          <span>
193	            Day <span class="text-flux-text-primary" data-testid="day-counter">{state.globalDay}</span>
194	          </span>
195	          <span aria-hidden="true">·</span>
196	          <span>
197	            Week <span class="text-flux-text-primary">{week}</span>
198	          </span>
199	          {phase && (
200	            <>
201	              <span aria-hidden="true">·</span>
202	              <span data-testid="phase-name">{phase.name}</span>
203	            </>
204	          )}
205	        </div>
206	      </header>
207	
208	      {!program ? (
209	        <div
210	          class="rounded-[2rem] bg-flux-card p-8 text-center shadow-flux-card"
211	          data-testid="no-program"
212	        >
213	          <p class="text-[10px] font-medium uppercase tracking-[0.2em] text-flux-text-tertiary">
214	            Empty
215	          </p>
216	          <h2 class="mt-3 text-lg font-medium text-flux-text-primary">No program loaded</h2>
217	          <p class="mt-2 text-sm text-flux-text-secondary">
218	            Programs are user-specific. Import one to begin, or generate with AI (coming soon).
219	          </p>
220	          <div class="mt-5 flex flex-wrap justify-center gap-2">
221	            <button
222	              type="button"
223	              class="rounded-full bg-flux-accent px-5 py-2.5 text-[11px] font-medium uppercase tracking-[0.15em] text-flux-card shadow-flux-soft transition-opacity hover:opacity-90"
224	              onClick={triggerProgramImport}
225	              data-testid="import-program-btn"
226	            >
227	              Import program file
228	            </button>
229	            <button
230	              type="button"
231	              class="cursor-not-allowed rounded-full bg-flux-soft px-5 py-2.5 text-[11px] font-medium uppercase tracking-[0.15em] text-flux-text-tertiary"
232	              disabled
233	              data-testid="generate-ai-btn"
234	              title="AI program generation is on the roadmap."
235	            >
236	              Generate with AI (soon)
237	            </button>
238	          </div>
239	          <input
240	            type="file"
241	            accept="application/json,.json"
242	            class="hidden"
243	            onChange={handleProgramImport}
244	            data-testid="import-program-input"
245	          />
246	        </div>
247	      ) : workout ? (
248	        <>
249	          <div
250	            class="overflow-hidden rounded-[2rem] bg-flux-card p-6 shadow-flux-card"
251	            data-testid="workout-card"
252	          >
253	            <p class="text-[10px] font-medium uppercase tracking-[0.2em] text-flux-text-tertiary">
254	              {workout.focus}
255	            </p>
256	            <h2
257	              class="mt-2 text-2xl font-medium leading-tight text-flux-text-primary"
258	              data-testid="workout-name"
259	            >
260	              {workout.name}
261	            </h2>
262	            <div class="mt-5 flex items-center gap-3">
263	              <div class="h-1.5 flex-1 overflow-hidden rounded-full bg-flux-soft">
264	                <div
265	                  class="h-full rounded-full bg-flux-accent transition-all"
266	                  style={{ width: `${progressPercent}%` }}
267	                  data-testid="session-progress"
